+      }
+
+      .hero {
+        margin-bottom: 2rem;
+      }
+
+      .hero h1 {
+        margin: 0 0 0.75rem;
+        font-size: clamp(2.6rem, 7vw, 4.5rem);
+        line-height: 0.95;
+      }
+
+      .hero p {
+        margin: 0;
+        max-width: 42rem;
+        color: var(--muted);
+        font-size: 1.15rem;
+        line-height: 1.6;
+      }
+
+      .install-panel,
+      .steps,
+      .sample {
+        background: rgba(255, 253, 250, 0.92);
