+        font-size: 0.8rem;
+        font-weight: 700;
+        letter-spacing: 0.2em;
+        text-transform: uppercase;
+      }
+
+      .bookmarklet {
+        display: inline-block;
+        padding: 0.95rem 1.4rem;
+        border: 2px dashed rgba(115, 48, 29, 0.45);
+        border-radius: 999px;
+        background: linear-gradient(180deg, var(--accent) 0%, var(--accent-strong) 100%);
+        color: #fff8f1;
+        font-size: 1rem;
+        font-weight: 700;
+        letter-spacing: 0.02em;
+        text-decoration: none;
+        cursor: grab;
+        user-select: none;
+      }
+
+      .bookmarklet:active {
+        cursor: grabbing;
+      }
+
+      .install-help {
+        margin: 1rem 0 0;
+        color: var(--muted);
+        font-size: 0.95rem;
+      }
+
+      .steps {
+        padding: 1.75rem 2rem;
+        margin: 0 0 1.5rem;
+      }
+
+      .steps ol {
+        margin: 0;
+        padding-left: 1.5rem;
+      }
+
+      .steps li + li {
+        margin-top: 1rem;
+      }
+
+      .steps strong {
+        display: block;
+        margin-bottom: 0.25rem;
+        font-size: 1.05rem;
+      }
+
+      .steps span {
+        color: var(--muted);
+        line-height: 1.6;
+      }
+
+      .sample {
+        padding: 1.5rem;
+      }
+
+      .sample-label {
+        margin: 0 0 0.9rem;
+        color: var(--muted);
+        font-size: 0.8rem;
+        font-weight: 700;
+        letter-spacing: 0.2em;
+        text-transform: uppercase;
+      }
+
+      pre {
+        margin: 0;
+        padding: 1.4rem;
+        overflow-x: auto;
+        border-radius: 1rem;
+        background: var(--sample);
+        color: var(--sample-text);
+        font-family: "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
+        font-size: 0.9rem;
+        line-height: 1.7;
+      }
+
+      code {
+        font-family: inherit;
+      }
+
+      @media (max-width: 42rem) {
+        .header-inner {
+          flex-direction: column;
+          gap: 0.35rem;
+        }
+
+        .content {
+          padding-top: 2.5rem;
+        }
+
+        .install-panel,
+        .steps,
+        .sample {
+          padding-left: 1.2rem;
+          padding-right: 1.2rem;
+        }
+      }
+    </style>
